before_code:
module priority_encoder_8bit(
  input [7:0] req,
  input valid_in,
  output reg [2:0] priority,
  output reg valid_out
);

  always @(req) begin
    if (req[7])
      priority = 3'b111;
    else if (req[6])
      priority = 3'b110;
    else if (req[5])
      priority = 3'b101;
    else if (req[4])
      priority = 3'b100;
    else if (req[3])
      priority = 3'b011;
    else if (req[2])
      priority = 3'b010;
    else if (req[1])
      priority = 3'b001;
    else
      priority = 3'b000;

    valid_out = |req;
  end

endmodule

after_code:
module priority_encoder_8bit(
  input [7:0] req,
  input valid_in,
  output reg [2:0] priority,
  output reg valid_out
);

  always @(req or valid_in) begin
    if (req[7])
      priority = 3'b111;
    else if (req[6])
      priority = 3'b110;
    else if (req[5])
      priority = 3'b101;
    else if (req[4])
      priority = 3'b100;
    else if (req[3])
      priority = 3'b011;
    else if (req[2])
      priority = 3'b010;
    else if (req[1])
      priority = 3'b001;
    else
      priority = 3'b000;

    valid_out = (|req) && valid_in;
  end

endmodule
